135	static int
136	array_strides_set(PyArrayObject *self, PyObject *obj, void *NPY_UNUSED(ignored))
137	{
138	    if (obj == NULL) {
139	        PyErr_SetString(PyExc_AttributeError,
140	                "Cannot delete array strides");
141	        return -1;
142	    }
143	
144	    /* Deprecated NumPy 2.4, 2025-05-11 */
145	    if (DEPRECATE("Setting the strides on a NumPy array has been deprecated in NumPy 2.4.\n"
146	                  "As an alternative, you can create a new view using np.lib.stride_tricks.as_strided."
147	                 ) < 0 ) {
148	        return -1;
149	    }
150	
151	    PyArray_Dims newstrides = {NULL, -1};
152	    PyArrayObject *new;
153	    npy_intp numbytes = 0;
154	    npy_intp offset = 0;
155	    npy_intp lower_offset = 0;
156	    npy_intp upper_offset = 0;
157	    Py_buffer view;
158	
159	    if (!PyArray_OptionalIntpConverter(obj, &newstrides) ||
160	        newstrides.len == -1) {
161	        PyErr_SetString(PyExc_TypeError, "invalid strides");
162	        return -1;
163	    }
164	    if (newstrides.len != PyArray_NDIM(self)) {
165	        PyErr_Format(PyExc_ValueError, "strides must be "       \
166	                     " same length as shape (%d)", PyArray_NDIM(self));
167	        goto fail;
168	    }
169	    new = self;
170	    while(PyArray_BASE(new) && PyArray_Check(PyArray_BASE(new))) {
171	        new = (PyArrayObject *)(PyArray_BASE(new));
172	    }
173	    /*
174	     * Get the available memory through the buffer interface on
175	     * PyArray_BASE(new) or if that fails from the current new
176	     */
177	    if (PyArray_BASE(new) &&
178	            PyObject_GetBuffer(PyArray_BASE(new), &view, PyBUF_SIMPLE) >= 0) {
179	        offset = PyArray_BYTES(self) - (char *)view.buf;
180	        numbytes = view.len + offset;
181	        PyBuffer_Release(&view);
182	    }
183	    else {
184	        PyErr_Clear();
185	        offset_bounds_from_strides(PyArray_ITEMSIZE(new), PyArray_NDIM(new),
186	                                   PyArray_DIMS(new), PyArray_STRIDES(new),
187	                                   &lower_offset, &upper_offset);
188	
189	        offset = PyArray_BYTES(self) - (PyArray_BYTES(new) + lower_offset);
190	        numbytes = upper_offset - lower_offset;
191	    }
192	
193	    /* numbytes == 0 is special here, but the 0-size array case always works */
194	    if (!PyArray_CheckStrides(PyArray_ITEMSIZE(self), PyArray_NDIM(self),
195	                              numbytes, offset,
196	                              PyArray_DIMS(self), newstrides.ptr)) {
197	        PyErr_SetString(PyExc_ValueError, "strides is not "\
198	                        "compatible with available memory");
199	        goto fail;
200	    }
201	    if (newstrides.len) {
202	        memcpy(PyArray_STRIDES(self), newstrides.ptr, sizeof(npy_intp)*newstrides.len);
203	    }
204	    PyArray_UpdateFlags(self, NPY_ARRAY_C_CONTIGUOUS | NPY_ARRAY_F_CONTIGUOUS |
205	                              NPY_ARRAY_ALIGNED);
206	    npy_free_cache_dim_obj(newstrides);
207	    return 0;
208	
209	 fail:
210	    npy_free_cache_dim_obj(newstrides);
211	    return -1;
212	}
