339	/*
340	 * If the type is changed.
341	 * Also needing change: strides, itemsize
342	 *
343	 * Either itemsize is exactly the same or the array is single-segment
344	 * (contiguous or fortran) with compatible dimensions The shape and strides
345	 * will be adjusted in that case as well.
346	 */
347	NPY_NO_EXPORT int
348	array_descr_set_internal(PyArrayObject *self, PyObject *arg)
349	{
350	    PyArray_Descr *newtype = NULL;
351	    assert(arg);
352	
353	    if (!(PyArray_DescrConverter(arg, &newtype)) ||
354	        newtype == NULL) {
355	        PyErr_SetString(PyExc_TypeError,
356	                "invalid data-type for array");
357	        return -1;
358	    }
359	    /* Check dtype and possibly give new dim & stride for last axis */
360	    int newnd;
361	    npy_intp *newdims = NULL;
362	    npy_intp *newstrides = NULL;
363	    /* Check whether the type is compatible, get pointers to dimensions and
364	       strides (can be from input or to newly allocated dim_array). */
365	    Py_SETREF(newtype, _check_compatibility_with_new_dtype(
366	                  self, newtype, &newnd, &newdims, &newstrides));
367	    if (newtype == NULL) {
368	        return -1;
369	    }
370	    if (newnd != PyArray_NDIM(self)) {
371	        /* Update self with new dim array created above (subarray dtype). */
372	        assert(newdims != PyArray_DIMS(self));
373	        npy_free_cache_dim_array(self);
374	        ((PyArrayObject_fields *)self)->nd = newnd;
375	        ((PyArrayObject_fields *)self)->dimensions = newdims;
376	        ((PyArrayObject_fields *)self)->strides = newstrides;
377	    }
378	    else { /* We keep our old dims (possibly changed inplace) */
379	        assert(newdims == PyArray_DIMS(self));
380	    }
381	    Py_DECREF(PyArray_DESCR(self));
382	    ((PyArrayObject_fields *)self)->descr = newtype;
383	    PyArray_UpdateFlags(self, NPY_ARRAY_UPDATE_ALL);
384	    return 0;
385	}
