406	static PyObject *
407	array_struct_get(PyArrayObject *self, void *NPY_UNUSED(ignored))
408	{
409	    PyArrayInterface *inter;
410	
411	    inter = (PyArrayInterface *)PyArray_malloc(sizeof(PyArrayInterface));
412	    if (inter==NULL) {
413	        return PyErr_NoMemory();
414	    }
415	    inter->two = 2;
416	    inter->nd = PyArray_NDIM(self);
417	    inter->typekind = PyArray_DESCR(self)->kind;
418	    inter->itemsize = PyArray_ITEMSIZE(self);
419	    inter->flags = PyArray_FLAGS(self);
420	    if (inter->flags & NPY_ARRAY_WARN_ON_WRITE) {
421	        /* Export a warn-on-write array as read-only */
422	        inter->flags = inter->flags & ~NPY_ARRAY_WARN_ON_WRITE;
423	        inter->flags = inter->flags & ~NPY_ARRAY_WRITEABLE;
424	    }
425	    /* reset unused flags */
426	    inter->flags &= ~(NPY_ARRAY_WRITEBACKIFCOPY | NPY_ARRAY_OWNDATA);
427	    if (PyArray_ISNOTSWAPPED(self)) inter->flags |= NPY_ARRAY_NOTSWAPPED;
428	    /*
429	     * Copy shape and strides over since these can be reset
430	     *when the array is "reshaped".
431	     */
432	    if (PyArray_NDIM(self) > 0) {
433	        inter->shape = (npy_intp *)PyArray_malloc(2*sizeof(npy_intp)*PyArray_NDIM(self));
434	        if (inter->shape == NULL) {
435	            PyArray_free(inter);
436	            return PyErr_NoMemory();
437	        }
438	        inter->strides = inter->shape + PyArray_NDIM(self);
439	        if (PyArray_NDIM(self)) {
440	            memcpy(inter->shape, PyArray_DIMS(self), sizeof(npy_intp)*PyArray_NDIM(self));
441	            memcpy(inter->strides, PyArray_STRIDES(self), sizeof(npy_intp)*PyArray_NDIM(self));
442	        }
443	    }
444	    else {
445	        inter->shape = NULL;
446	        inter->strides = NULL;
447	    }
448	    inter->data = PyArray_DATA(self);
449	    if (PyDataType_HASFIELDS(PyArray_DESCR(self))) {
450	        inter->descr = arraydescr_protocol_descr_get(PyArray_DESCR(self), NULL);
451	        if (inter->descr == NULL) {
452	            PyErr_Clear();
453	        }
454	        else {
455	            inter->flags &= NPY_ARR_HAS_DESCR;
456	        }
457	    }
458	    else {
459	        inter->descr = NULL;
460	    }
461	    PyObject *ret = PyCapsule_New(inter, NULL, gentype_struct_free);
462	    if (ret == NULL) {
463	        return NULL;
464	    }
465	    Py_INCREF(self);
466	    if (PyCapsule_SetContext(ret, self) < 0) {
467	        return NULL;
468	    }
469	    return ret;
470	}
