485	/*
486	 * Fetches the real or imaginary part of an array. If `need_view` is set the return
487	 * cannot be a copy (must be a view).
488	 * If `need_view` is zero it will return the `ufunc`s result (a new array) and set it
489	 * to read-only.
490	 */
491	static PyObject *
492	_get_part(PyArrayObject *self, PyObject *ufunc, PyBoundArrayMethodObject *meth, int need_view)
493	{
494	    PyObject *ret = NULL;
495	    PyArray_Descr *descrs[2] = {PyArray_DESCR(self), NULL};
496	    PyArray_Descr *loop_descrs[2] = {NULL, NULL};
497	    npy_intp view_offset = NPY_MIN_INTP;
498	    int res = meth->method->resolve_descriptors(
499	        meth->method, meth->dtypes, descrs, loop_descrs, &view_offset);
500	    if (res < 0) {
501	        return NULL;
502	    }
503	    if (view_offset != NPY_MIN_INTP) {
504	        Py_INCREF(loop_descrs[1]);
505	        ret = PyArray_NewFromDescr_int(
506	            Py_TYPE(self), loop_descrs[1],
507	            PyArray_NDIM(self), PyArray_DIMS(self),
508	            PyArray_STRIDES(self), PyArray_BYTES(self) + view_offset,
509	            PyArray_FLAGS(self), (PyObject *)self, (PyObject *)self,
510	            _NPY_ARRAY_ENSURE_DTYPE_IDENTITY);
511	    }
512	    else if (!need_view) {
513	        // resolve_descriptors was successful, but view_offset is not set so we call
514	        // the ufunc to let it deal with the (potential) complexity.
515	        ret = PyArray_GenericUnaryFunction(self, ufunc);
516	        if (ret != NULL && PyArray_Check(ret)) {
517	            // Make result read-only, since otherwise `arr.imag[...] = val`
518	            // would for example work.
519	            PyArray_CLEARFLAGS((PyArrayObject *)ret, NPY_ARRAY_WRITEABLE);
520	        }
521	    }
522	
523	    Py_DECREF(loop_descrs[0]);
524	    Py_DECREF(loop_descrs[1]);
525	    return ret;
526	}
